        return None

    pixel_cap = len(raw_prefix) // channels
    if pixel_cap <= 0:
        return None

    target_bits = max_bytes * 8
    max_bits_available = pixel_cap * k
    bits_to_take = min(target_bits, max_bits_available)
    bytes_to_take = bits_to_take // 8
    if bytes_to_take <= 0:
        return None

