            b = 0
            t0 = byte_i * 8
            for j in range(8):
                t = t0 + j
                pixel_i = t // k
                mi = t % k
                ch = mask[mi]
                bit = bits_by_ch[ch][pixel_i]
                b |= (bit & 1) << j
            out[byte_i] = b

